const catNames = {
    national: "জাতীয় দৈনিক পত্রিকা",
    online: "জনপ্রিয় অনলাইন পোর্টাল",
    tv: "টিভি চ্যানেল ও নিউজ",
    international: "আন্তর্জাতিক সংবাদ",
    sports: "খেলাধুলা ও বিনোদন",
    district: "জেলা ভিত্তিক পত্রিকা"
};

const catIcons = {
    national: "fa-landmark",
    online: "fa-globe",
    tv: "fa-tv",
    international: "fa-globe-americas",
    sports: "fa-futbol",
    district: "fa-map-marker-alt"
};

// Render Portal Dynamically on Homepage
function renderPortal() {
    const container = document.getElementById('portalIndex');
    if (!container) return; // Exit if not on homepage

    let html = '';

    // Loop through categories
    for (const key in catNames) {
        const sites = newsDatabase.filter(site => site.cat === key);

        html += `
        <div class="cat-box" id="${key}">
            <div class="cat-header">
                <h2><i class="fas ${catIcons[key]}"></i> ${catNames[key]}</h2>
                <span class="badge">${sites.length}+ সাইট</span>
            </div>
            <div class="news-grid">
                ${sites.map(site => `
                    <div class="news-card" data-title="${site.name}" onclick="openReader('${site.url}', '${site.name}')">
                        <img src="https://www.google.com/s2/favicons?sz=128&domain=${site.url}" alt="${site.name}" />
                        <span>${site.name}</span>
                    </div>
                `).join('')}
            </div>
        </div>`;
    }
    container.innerHTML = html;
}

// --- FILTER FUNCTION ---
function proFilter() {
    let input = document.getElementById('proSearch').value.toLowerCase();
    let cards = document.querySelectorAll('.news-card');
    cards.forEach(card => {
        let name = card.getAttribute('data-title').toLowerCase();
        card.style.display = name.includes(input) ? "flex" : "none";
    });
}

// --- DATE SETTER ---
function setDate() {
    const dateOpt = { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' };
    const dateElem = document.getElementById('proDate');
    if (dateElem) {
        dateElem.innerText = new Date().toLocaleDateString('bn-BD', dateOpt);
    }
}

// --- THEME TOGGLER ---
function toggleTheme() {
    const body = document.body;
    const toggleBtn = document.getElementById('themeToggle');
    if (body.classList.contains('dark-mode')) {
        body.classList.remove('dark-mode');
        toggleBtn.innerHTML = '<i class="fas fa-moon"></i>';
        localStorage.setItem('theme', 'light');
    } else {
        body.classList.add('dark-mode');
        toggleBtn.innerHTML = '<i class="fas fa-sun"></i>';
        localStorage.setItem('theme', 'dark');
    }
}

// --- MODAL READER HANDLERS ---
function openReader(url, name) {
    document.getElementById('readerTitle').innerText = "পড়ছেন: " + name;
    document.getElementById('readerFrame').src = url;
    document.getElementById('readerExt').href = url;
    document.getElementById('proReader').style.display = "flex";
    document.body.style.overflow = "hidden";
}

function closeReader() {
    document.getElementById('proReader').style.display = "none";
    document.getElementById('readerFrame').src = "";
    document.body.style.overflow = "auto";
}

// Execute on load
document.addEventListener('DOMContentLoaded', () => {
    renderPortal();
    setDate();

    // Check stored theme
    if (localStorage.getItem('theme') === 'dark') {
        document.body.classList.add('dark-mode');
        document.getElementById('themeToggle').innerHTML = '<i class="fas fa-sun"></i>';
    }
});

// ESC key to close modal
document.addEventListener('keydown', function(e) {
    if (e.key === "Escape") closeReader();
});
